import logging
import logging.handlers
import os

# Define the log directory
LOG_DIR = '/var/log/application'

# Create the log directory if it doesn't exist
os.makedirs(LOG_DIR, exist_ok=True)

# Define log file path
LOG_FILE = os.path.join(LOG_DIR, 'app.log')

# --- Logger Configuration ---
# Get the root logger
logger = logging.getLogger()
logger.setLevel(logging.INFO)  # Set the minimum logging level

# --- Formatter Configuration ---
# Define a formatter for the log messages
formatter = logging.Formatter(
    '%(asctime)s - %(levelname)s - %(process)d - %(thread)d - %(name)s - %(filename)s:%(lineno)d - %(message)s'
)

# --- Handler Configuration ---

# 1. TimedRotatingFileHandler for log rotation by time
# This handler rotates logs every day at midnight and keeps 7 backup files.
file_handler = logging.handlers.TimedRotatingFileHandler(
    LOG_FILE,
    when='midnight',  # Rotate at midnight
    interval=1,       # Every day
    backupCount=7,    # Keep 7 days of backups
    encoding='utf-8'  # Specify encoding
)
file_handler.setFormatter(formatter)
file_handler.setLevel(logging.INFO) # Minimum level for this handler
logger.addHandler(file_handler)

